import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases","description":"","frontmatter":{"url":"https://arxiv.org/abs/2512.10398","title":"Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases","date":"2025-12-11T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2025-12-11-confucius-code-agent.md","filePath":"research/ai-articles/scored/2025-12-11-confucius-code-agent.md","lastUpdated":1779796674000}'),d={name:"research/ai-articles/scored/2025-12-11-confucius-code-agent.md"};function n(s,t,l,c,i,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="confucius-code-agent-scalable-agent-scaffolding-for-real-world-codebases" tabindex="-1">Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases <a class="header-anchor" href="#confucius-code-agent-scalable-agent-scaffolding-for-real-world-codebases" aria-label="Permalink to &quot;Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/abs/2512.10398" target="_blank" rel="noreferrer">https://arxiv.org/abs/2512.10398</a><br><strong>作者</strong>：Sherman Wong 等 11 位（Harvard / MIT）<br><strong>發表日期</strong>：2025-12-11<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="研究背景與動機" tabindex="-1">研究背景與動機 <a class="header-anchor" href="#研究背景與動機" aria-label="Permalink to &quot;研究背景與動機&quot;">​</a></h3><p>現有軟體工程 Agent 在小型代碼庫表現尚可，但面對工業規模（數百萬行）的大型代碼庫時，因 context window 耗盡、工具可靠性不足、跨 session 記憶缺失等問題而失效。Confucius Code Agent（CCA）正是為解決這三大挑戰而設計。</p><h3 id="系統設計哲學" tabindex="-1">系統設計哲學 <a class="header-anchor" href="#系統設計哲學" aria-label="Permalink to &quot;系統設計哲學&quot;">​</a></h3><p>CCA 以三個體驗軸為設計基礎，刻意解耦：</p><table tabindex="0"><thead><tr><th>軸向</th><th>定義</th><th>實踐方式</th></tr></thead><tbody><tr><td><strong>AX（Agent 體驗）</strong></td><td>Agent 能有效推理與行動</td><td>結構化壓縮記憶</td></tr><tr><td><strong>UX（用戶體驗）</strong></td><td>透明、可解釋的執行軌跡</td><td>詳細可讀的 trace logs</td></tr><tr><td><strong>DX（開發者體驗）</strong></td><td>可觀測的推理與工具使用</td><td>評估機制與 observability</td></tr></tbody></table><h3 id="四大核心功能" tabindex="-1">四大核心功能 <a class="header-anchor" href="#四大核心功能" aria-label="Permalink to &quot;四大核心功能&quot;">​</a></h3><h4 id="f1-context-管理-階層式工作記憶" tabindex="-1">F1：Context 管理（階層式工作記憶） <a class="header-anchor" href="#f1-context-管理-階層式工作記憶" aria-label="Permalink to &quot;F1：Context 管理（階層式工作記憶）&quot;">​</a></h4><p>當 prompt 長度接近閾值，「Architect」規劃者 Agent 會摘要關鍵資訊類別，同時保留最近的原始歷史。這使系統能在工業規模代碼庫上執行長期軟體工程任務。實驗顯示，context 管理讓 Claude 4 Sonnet 的解決率提升 <strong>+6.6 個百分點</strong>。</p><h4 id="f2-持久筆記-跨-session-學習" tabindex="-1">F2：持久筆記（跨 Session 學習） <a class="header-anchor" href="#f2-持久筆記-跨-session-學習" aria-label="Permalink to &quot;F2：持久筆記（跨 Session 學習）&quot;">​</a></h4><p>專用 Agent 將執行軌跡提煉為持久 Markdown 筆記，包含：</p><ul><li>成功策略記錄</li><li>失敗模式的「後見之明筆記」（hindsight notes）</li></ul><p>跨 session 重跑任務時，token 成本降低約 11k（~11%），解決率提升 <strong>+1.4 個百分點</strong>。</p><h4 id="f3-模組化擴充-工具組合" tabindex="-1">F3：模組化擴充（工具組合） <a class="header-anchor" href="#f3-模組化擴充-工具組合" aria-label="Permalink to &quot;F3：模組化擴充（工具組合）&quot;">​</a></h4><p>文件編輯、CLI 執行、程式碼搜尋等工具組件透過型別化回調（typed callbacks）連接到 orchestrator，實現模組組合與清晰的關注點分離。</p><h4 id="f4-meta-agent-自動構建" tabindex="-1">F4：Meta-Agent（自動構建） <a class="header-anchor" href="#f4-meta-agent-自動構建" aria-label="Permalink to &quot;F4：Meta-Agent（自動構建）&quot;">​</a></h4><p>Meta-Agent 透過「構建—測試—改進」循環，自動合成提示詞與配置。這是一個自我優化層，根據評估反饋不斷精煉 Agent 本身。</p><h3 id="效能結果-swe-bench-pro" tabindex="-1">效能結果（SWE-Bench-Pro） <a class="header-anchor" href="#效能結果-swe-bench-pro" aria-label="Permalink to &quot;效能結果（SWE-Bench-Pro）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>CCA 結果</th><th>對比基準</th></tr></thead><tbody><tr><td>Claude 4 Sonnet</td><td>45.5%</td><td>SWE-Agent 42.7%</td></tr><tr><td>Claude 4.5 Sonnet</td><td>52.7%</td><td>Live-SWE-Agent 45.8%</td></tr><tr><td>Claude 4.5 Opus</td><td>54.3%</td><td>達到商業系統水準</td></tr></tbody></table><p><strong>關鍵洞見</strong>：弱模型 + 強 scaffold &gt; 強模型 + 弱 scaffold。Scaffolding 的品質比底層模型能力更具決定性。</p><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>Context 壓縮不是優化而是基礎</strong>：CCA 的 Architect 摘要模式與 cc-workspace 的 <code>/compact</code> 策略高度一致，可借鑒其「關鍵資訊分類摘要 + 保留近期原始歷史」的雙層結構。</li><li><strong>持久筆記作為跨 Session 記憶</strong>：類似 <code>auto-memory</code> 機制，但 CCA 更明確地將「失敗模式」也寫入筆記，值得納入 session-learner skill。</li><li><strong>Meta-Agent 自動優化</strong>：與 harness-eval skill 的「Ratchet 評分」理念相通，未來可考慮引入自動化 prompt 優化循環。</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>context 分層壓縮、持久筆記、Meta-Agent 三個模式均可直接應用於 cc-workspace 設計改善</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>「後見之明筆記」和 Meta-Agent 自動優化是新穎概念；但整體仍在既有 scaffold 框架範圍內</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>SWE-Bench-Pro 量化結果，有 ablation study（+6.6pp context、+1.4pp memory），可重現</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>四大功能有具體機制描述，AX/UX/DX 三軸解耦哲學有明確實踐方式</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>針對大型代碼庫設計，但 context 管理和持久記憶模式可廣泛應用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.65/10</strong></td><td>8×0.3 + 7×0.2 + 8×0.2 + 8×0.15 + 7×0.15 = 2.4+1.4+1.6+1.2+1.05</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/rules/core.md</code>（持久筆記模式）或 <code>.claude/refs/session-management.md</code>（context 分層策略）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>將「hindsight notes（失敗模式）」概念加入 session-learner skill</li><li>參考 Architect 摘要模式優化 context-monitor-table.md 的分層觸發策略</li></ul>',31)])])}const b=e(d,[["render",n]]);export{f as __pageData,b as default};
